  libera(lista29);
  libera(lista789);
  libera(lista24);
  libera(lista24589);
}

void testGrande(int nreps) {
  // Se eliminan rangos aleatorios de una lista de 10000 elementos hasta
  // que la lista quede vacia.
  for (int r= 0; r<nreps; r++) {
    int ar[LENLIS];
    for (int k= 0; k<LENLIS; k++)
      ar[k]= 1;
    Nodo *lis= listaGrande(0, LENLIS-1);
    revisa(lis, ar, LENLIS);
    while (lis!=NULL) {
      int i= random()%LENLIS;
      int j= random()%LENLIS;
      if (i>j) {
        int tmp= i;
        i= j;
        j= tmp;
      }
      eliminarRango(&lis, i, j);
      for (int k= i; k<=j; k++)
        ar[k]= 0;
      revisa(lis, ar, LENLIS);
    }
  }
}

// ----------------------------------------------------
// Benchmark

long benchRango(int nreps) {
  long ini= getTime();
  for (int r= 0; r<nreps; r++) {
    Nodo *lis= listaGrande(0, LENLIS-1);
    while (lis!=NULL) {
      int i= random()%LENLIS;
      int j= random()%LENLIS;
      if (i>j) {
        int tmp= i;
        i= j;
        j= tmp;
      }
      eliminarRango(&lis, i, j);
    }
  }
  return getTime()-ini;
}

