#include <stdio.h>
#include <stdlib.h>

#include "rango.h"

void eliminarRango(Nodo **phead, double y, double z) {
    // Recorremos la lista usando un puntero a puntero, lo que nos permite
    // modificar tanto la cabeza como el campo prox del nodo anterior.
    Nodo **pp = phead;
    while (*pp != NULL) {
        Nodo *nodo = *pp;
        if (nodo->x < y) {
            // El elemento está antes del rango: avanzamos.
            pp = &nodo->prox;
        } else if (nodo->x <= z) {
            // El elemento está dentro del rango [y, z]: lo eliminamos.
            *pp = nodo->prox;
            free(nodo);
        } else {
            // El elemento está después del rango. Como la lista está
            // ordenada, los siguientes también estarán después del rango.
            break;
        }
    }
}
